class Solution:
    def maxStability(self, n: int, edges: List[List[int]], k: int) -> int:
        graph = [[] for _ in range(n)]
        for u, v, s, must in edges:
            graph[u].append((v, s, must))
            graph[v].append((u, s, must))

        def dfs(node, parent, visited, must):
            visited.add(node)
            for neighbor, strength, neighbor_must in graph[node]:
                if neighbor == parent:
                    continue
                if neighbor_must == 1:
                    must.add(neighbor)
                else:
                    dfs(neighbor, node, visited, must)

        must = set()
        dfs(0, -1, set(), must)

        if len(must) < n - 1:
            return -1

        must = list(must)
        graph = [[] for _ in range(n)]
        for u, v, s, must_i in edges:
            if u in must or v in must:
                graph[u].append((v, s, must_i))
                graph[v].append((u, s, must_i))

        parent = [-1] * n
        rank = [0] * n
        def find(node):
            if parent[node] != node:
                parent[node] = find(parent[node])
            return parent[node]

        def union(node1, node2):
            root1 = find(node1)
            root2 = find(node2)
            if root1 != root2:
                if rank[root1] > rank[root2]:
                    parent[root2] = root1
                else:
                    parent[root1] = root2
                    if rank[root1] == rank[root2]:
                        rank[root2] += 1

        for u, v, s, must_i in edges:
            if must_i == 0:
                union(u, v)

        for u, v, s, must_i in edges:
            if must_i == 0:
                if find(u) != find(v):
                    union(u, v)

        if find(0) != find(1):
            return -1

        min_strength = float('inf')
        for u, v, s, must_i in edges:
            if must_i == 0:
                min_strength = min(min_strength, s)

        for u, v, s, must_i in edges:
            if must_i == 1:
                min_strength = min(min_strength, s)

        for u, v, s, must_i in edges:
            if must_i == 0:
                if k > 0:
                    k -= 1
                    min_strength = min(min_strength, s * 2)

        return min_strength
